import React, { useState, useCallback, useEffect } from 'react';
import axios from 'axios';
import * as XLSX from 'xlsx';
import './KhaiBaoCoSo.css';
import speciesOptions from '../data/speciesData';
import { jwtDecode } from 'jwt-decode';
import { useNavigate } from 'react-router-dom';

function KhaiBaoCoSo() {
  const navigate = useNavigate();

  const initialFormState = {
    tenCoSo: '', tinhThanhPho: '', xaPhuong: '', diaChiCoSo: '', vido: '', kinhdo: '',
    loaiHinhCoSo: '', ngayThanhLap: '', giayPhepKinhDoanh: '',
    tenNguoiDaiDien: '', namSinh: '', soCCCD: '', ngayCapCCCD: '', noiCapCCCD: '',
    soDienThoaiNguoiDaiDien: '', diaChiNguoiDaiDien: '', emailNguoiDaiDien: '',
    mucDichNuoi: '', hinhThucNuoi: '', maSoCoSoGayNuoi: '', tongDan: '',
    loaiHinhKinhDoanhGo: '', nganhNgheKinhDoanhGo: '', khoiLuong: '',
    loaiHinhCheBienGo: '', nguonGocGo: '',
    loaiCoSoDangKy: '',
    tenLamSan: '', tenKhoaHoc: '',
    issueDate: '', expiryDate: '',
    trangThai: 'Đang hoạt động',
  };

  const [formData, setFormData] = useState(initialFormState);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);
  const [successMessage, setSuccessMessage] = useState(null);
  const [csvFile, setCsvFile] = useState(null);
  const [excelData, setExcelData] = useState([]);
  const [isLoading, setIsLoading] = useState(false);
  const [isAdmin, setIsAdmin] = useState(false);
  const [message, setMessage] = useState({ type: '', text: '' });

  useEffect(() => {
    // ... Giữ nguyên logic của bạn ...
  }, [navigate]);

  const handleChange = useCallback((e) => {
    const { name, value } = e.target;
    setFormData(prevData => ({ ...prevData, [name]: value }));
  }, []);

  const resetForm = useCallback(() => {
    setFormData(initialFormState);
    setError(null);
    setSuccessMessage(null);
    setMessage({ type: '', text: '' });
  }, [initialFormState]);

  // ========================================================================
  // === HÀM handleSubmit ĐÃ ĐƯỢC CẬP NHẬT CHÍNH XÁC ĐỂ GOM DỮ LIỆU     ===
  // ========================================================================
  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError(null);
    setSuccessMessage(null);
    setMessage({ type: '', text: '' });

    const token = localStorage.getItem('token');
    if (!token) {
      setMessage({ type: 'error', text: 'Bạn chưa đăng nhập. Vui lòng đăng nhập lại.' });
      setLoading(false);
      navigate('/login');
      return;
    }

    try {
        const submissionData = { ...formData };
        submissionData.products = [];

        // Kiểm tra và gom dữ liệu nếu người dùng có nhập thông tin sản phẩm/loài nuôi
        if (submissionData.tenLamSan) {
            let productInfo = {};

            if (submissionData.loaiCoSoDangKy === 'Đăng ký cơ sở gây nuôi') {
                productInfo = {
                    tenLamSan: submissionData.tenLamSan,
                    tenKhoaHoc: speciesOptions.find(s => s.name === submissionData.tenLamSan)?.scientificName || '',
                    khoiLuong: submissionData.tongDan, // 'khoiLuong' trong schema sẽ lưu 'tongDan'
                    donViTinh: 'cá thể',
                    mucDichNuoi: submissionData.mucDichNuoi,
                    hinhThucNuoi: submissionData.hinhThucNuoi,
                    maSoCoSoGayNuoi: submissionData.maSoCoSoGayNuoi
                };
            } else if (submissionData.loaiCoSoDangKy === 'Đăng ký cơ sở kinh doanh, chế biến gỗ') {
                productInfo = {
                    tenLamSan: submissionData.tenLamSan,
                    tenKhoaHoc: submissionData.tenKhoaHoc,
                    khoiLuong: submissionData.khoiLuong,
                    donViTinh: 'm³',
                    loaiHinhCheBienGo: submissionData.loaiHinhCheBienGo,
                    nguonGocGo: submissionData.nguonGocGo
                };
            }
            submissionData.products.push(productInfo);
        }

        // Xóa các trường đã được gom vào mảng `products` khỏi đối tượng gửi đi
        const fieldsToDelete = [
            'tenLamSan', 'tenKhoaHoc', 'khoiLuong', 'tongDan', 'loaiHinhCheBienGo', 
            'nguonGocGo', 'mucDichNuoi', 'hinhThucNuoi', 'maSoCoSoGayNuoi'
        ];
        fieldsToDelete.forEach(field => delete submissionData[field]);

        const response = await axios.post('http://localhost:10000/api/farms', submissionData, {
            headers: { Authorization: `Bearer ${token}` }
        });

        setSuccessMessage('Đăng ký cơ sở thành công!');
        setMessage({ type: 'success', text: 'Đăng ký cơ sở thành công!' });
        resetForm();
    } catch (err) {
        // ... Xử lý lỗi giữ nguyên như file của bạn ...
    } finally {
        setLoading(false);
    }
  };
  
  // ========================================================================
  // === HÀM handleFileUpload ĐÃ ĐƯỢC CẬP NHẬT CHÍNH XÁC ĐỂ GOM DỮ LIỆU  ===
  // ========================================================================
  const handleFileUpload = (e) => {
    const file = e.target.files[0];
    if (file) {
      setCsvFile(file);
      const reader = new FileReader();
      reader.onload = (event) => {
        const data = new Uint8Array(event.target.result);
        const workbook = XLSX.read(data, { type: 'array' });
        const sheetName = workbook.SheetNames[0];
        const worksheet = workbook.Sheets[sheetName];
        const json = XLSX.utils.sheet_to_json(worksheet, { header: 1 });
        const headers = json[0];
        const rows = json.slice(1);
        const columnMapping = { /* ... Giữ nguyên mapping của bạn ... */ };

        const parsedData = rows.map(row => {
            const rowObject = {};
            headers.forEach((header, index) => {
                const englishKey = columnMapping[header.trim()];
                if (englishKey) {
                    rowObject[englishKey] = row[index];
                }
            });

            // Logic gom dữ liệu cho từng dòng trong CSV
            rowObject.products = [];
            if (rowObject.tenLamSan) {
                let productInfo = {};
                if (rowObject.loaiCoSoDangKy === 'Đăng ký cơ sở gây nuôi') {
                    productInfo = {
                        tenLamSan: rowObject.tenLamSan,
                        tenKhoaHoc: rowObject.tenKhoaHoc,
                        khoiLuong: rowObject.tongDan,
                        donViTinh: 'cá thể',
                        mucDichNuoi: rowObject.mucDichNuoi,
                        hinhThucNuoi: rowObject.hinhThucNuoi,
                        maSoCoSoGayNuoi: rowObject.maSoCoSoGayNuoi
                    };
                } else if (rowObject.loaiCoSoDangKy === 'Đăng ký cơ sở kinh doanh, chế biến gỗ') {
                    productInfo = {
                        tenLamSan: rowObject.tenLamSan,
                        tenKhoaHoc: rowObject.tenKhoaHoc,
                        khoiLuong: rowObject.khoiLuong,
                        donViTinh: 'm³',
                        loaiHinhCheBienGo: rowObject.loaiHinhCheBienGo,
                        nguonGocGo: rowObject.nguonGocGo
                    };
                }
                rowObject.products.push(productInfo);
            }

            // Xóa các trường đã gom
            const fieldsToDelete = [
                'tenLamSan', 'tenKhoaHoc', 'khoiLuong', 'tongDan', 'loaiHinhCheBienGo', 
                'nguonGocGo', 'mucDichNuoi', 'hinhThucNuoi', 'maSoCoSoGayNuoi'
            ];
            fieldsToDelete.forEach(field => delete rowObject[field]);
            
            return rowObject;
        });
        
        setExcelData(parsedData);
        setMessage({ type: 'info', text: `Đã đọc ${parsedData.length} dòng. Nhấn "Tải lên" để lưu.` });
      };
      reader.readAsArrayBuffer(file);
    }
  };
  
  // Các hàm còn lại giữ nguyên
  const handleBulkSubmit = async () => { /* ... */ };
  const resetCsvUpload = () => { /* ... */ };

  return (
    <div className="khai-bao-container">
      {/* TOÀN BỘ PHẦN GIAO DIỆN JSX GIỮ NGUYÊN 100% NHƯ FILE CHUẨN CỦA BẠN */}
      <h2>Đăng ký cơ sở</h2>
      {/* ... */}
      <form onSubmit={handleSubmit} className="khai-bao-form">
        {/* ... */}
      </form>
      {/* ... */}
    </div>
  );
}

export default KhaiBaoCoSo;
